local nR = me:RandomInt(1, 9) 
if nR <= 2 then
	me:AddMsg(XT("[NAME]随手破开聚合物，一缕闪光黏液渗出。收集之时，总令人有些毛骨悚然。"));
	me:DropAwardItem("Item_SoulCrystalYou", 1);
elseif nR > 2 and nR <= 4 then
	me:AddMsg(XT("[NAME]果断破开聚合物，一枚温润雅致的碎片映入眼帘，其中灵光令人心神安定。"));
	me:DropAwardItem("Item_SoulCrystalNing", 1);	
elseif nR > 4 and nR <=6 then
	me:AddMsg(XT("[NAME]小心剖开聚合物，一枚璀璨而坚实的晶体跃入眼中，竟忍不住朗声一笑。"));
	me:DropAwardItem("Item_SoulCrystalLing", 1);
elseif nR == 7 then
	me:AddMsg(XT("[NAME]小心剖开聚合物，刺骨寒意陡然渗出，令人倒吸一口凉气！"));
	me:DropAwardItem("Item_SoulPearl", 1);
else
	me:AddMsg("[NAME] Broke open the Agglomeration but it was just reflected light.");	
end
story:RemoveBindItem();


