			me:AddModifier("HotStory_BuildingLv");
		elseif nD == 4 then
			me:AddMsg(XT("[NAME]的农耕见识有所增长。"));
			me:AddModifier("HotStory_FarmingLv");
		elseif nD == 5 then
			me:AddMsg(XT("[NAME]的采矿见识有所增长。"));
			me:AddModifier("HotStory_MiningLv");
		elseif nD == 6 then
			me:AddMsg(XT("[NAME]对雅艺的理解有所增长。"));
			me:AddModifier("HotStory_ArtLv");
		elseif nD == 7 then
